   154ŌåÆ// ensurePanelsHaveUniqueIds ensures all panels have unique IDs
   155ŌåÆfunc ensurePanelsHaveUniqueIds(dashboard map[string]interface{}) {
   156ŌåÆ	panels := getPanels(dashboard)
   157ŌåÆ	if len(panels) == 0 {
   158ŌåÆ		return
   159ŌåÆ	}
   160ŌåÆ
   161ŌåÆ	ids := make(map[float64]bool)
   162ŌåÆ	nextPanelId := getNextPanelId(panels)
   163ŌåÆ
   164ŌåÆ	for _, panel := range panels {
   165ŌåÆ		if panelID, ok := panel["id"].(float64); ok && panelID > 0 {
   166ŌåÆ			if ids[panelID] {
   167ŌåÆ				// Duplicate ID found, assign new one
   168ŌåÆ				panel["id"] = float64(nextPanelId)
   169ŌåÆ				nextPanelId++
   170ŌåÆ			} else {
   171ŌåÆ				// Valid unique ID, keep it
   172ŌåÆ				ids[panelID] = true
   173ŌåÆ			}
   174ŌåÆ		} else {
   175ŌåÆ			// No ID or invalid ID, assign new one
   176ŌåÆ			panel["id"] = float64(nextPanelId)
   177ŌåÆ			nextPanelId++
   178ŌåÆ		}
   179ŌåÆ	}
   180ŌåÆ}
