   182ŌåÆ// getNextPanelId finds the next available panel ID
   183ŌåÆfunc getNextPanelId(panels []map[string]interface{}) int {
   184ŌåÆ	max := 0
   185ŌåÆ	for _, panel := range panels {
   186ŌåÆ		if panelID, ok := panel["id"].(float64); ok && panelID > 0 {
   187ŌåÆ			if int(panelID) > max {
   188ŌåÆ				max = int(panelID)
   189ŌåÆ			}
   190ŌåÆ		}
   191ŌåÆ	}
   192ŌåÆ	return max + 1
   193ŌåÆ}
