   195ŌåÆ// sortPanelsByGridPos sorts panels by grid position (y first, then x)
   196ŌåÆfunc sortPanelsByGridPos(dashboard map[string]interface{}) {
   197ŌåÆ	panels := getPanels(dashboard)
   198ŌåÆ	if len(panels) == 0 {
   199ŌåÆ		return
   200ŌåÆ	}
   201ŌåÆ
   202ŌåÆ	sort.SliceStable(panels, func(i, j int) bool {
   203ŌåÆ		panelA := panels[i]
   204ŌåÆ		panelB := panels[j]
   205ŌåÆ
   206ŌåÆ		gridPosA, okA := panelA["gridPos"].(map[string]interface{})
   207ŌåÆ		gridPosB, okB := panelB["gridPos"].(map[string]interface{})
   208ŌåÆ
   209ŌåÆ		if !okA || !okB {
   210ŌåÆ			return false
   211ŌåÆ		}
   212ŌåÆ
   213ŌåÆ		yA, okA := gridPosA["y"].(float64)
   214ŌåÆ		yB, okB := gridPosB["y"].(float64)
   215ŌåÆ
   216ŌåÆ		if !okA || !okB {
   217ŌåÆ			return false
   218ŌåÆ		}
   219ŌåÆ
   220ŌåÆ		if yA == yB {
   221ŌåÆ			// Same row, sort by x
   222ŌåÆ			xA, okA := gridPosA["x"].(float64)
   223ŌåÆ			xB, okB := gridPosB["x"].(float64)
   224ŌåÆ
   225ŌåÆ			if !okA || !okB {
   226ŌåÆ				return false
   227ŌåÆ			}
   228ŌåÆ
   229ŌåÆ			return xA < xB
   230ŌåÆ		}
   231ŌåÆ
   232ŌåÆ		return yA < yB
   233ŌåÆ	})
   234ŌåÆ}
