   823ŌåÆ// cleanupPanels cleans up panels and ensures panels property always exists
   824ŌåÆfunc cleanupPanels(dashboard map[string]interface{}) {
   825ŌåÆ	if panels, ok := dashboard["panels"].([]interface{}); ok {
   826ŌåÆ		// Filter out repeated panels (matches frontend getPanelSaveModels behavior)
   827ŌåÆ		// Frontend filters: !(panel.repeatPanelId || panel.repeatedByRow)
   828ŌåÆ		filteredPanels := []interface{}{}
   829ŌåÆ		for _, panelInterface := range panels {
   830ŌåÆ			if panel, ok := panelInterface.(map[string]interface{}); ok {
   831ŌåÆ				// Skip panels with repeatPanelId or repeatedByRow
   832ŌåÆ				if _, hasRepeatPanelId := panel["repeatPanelId"]; hasRepeatPanelId {
   833ŌåÆ					continue
   834ŌåÆ				}
   835ŌåÆ				if _, hasRepeatedByRow := panel["repeatedByRow"]; hasRepeatedByRow {
   836ŌåÆ					continue
   837ŌåÆ				}
   838ŌåÆ				filteredPanels = append(filteredPanels, panel)
   839ŌåÆ			}
   840ŌåÆ		}
   841ŌåÆ
   842ŌåÆ		cleanupPanelList(filteredPanels)
   843ŌåÆ		sortPanelsByGridPosition(filteredPanels)
   844ŌåÆ		dashboard["panels"] = filteredPanels
   845ŌåÆ	} else {
   846ŌåÆ		// Ensure panels property exists even if empty (matches frontend behavior)
   847ŌåÆ		dashboard["panels"] = []interface{}{}
   848ŌåÆ	}
   849ŌåÆ}
