   869ŌåÆ// sortPanelsByGridPosition sorts panels by grid position (matches frontend sortPanelsByGridPos behavior)
   870ŌåÆfunc sortPanelsByGridPosition(panels []interface{}) {
   871ŌåÆ	sort.SliceStable(panels, func(i, j int) bool {
   872ŌåÆ		panelA, okA := panels[i].(map[string]interface{})
   873ŌåÆ		panelB, okB := panels[j].(map[string]interface{})
   874ŌåÆ		if !okA || !okB {
   875ŌåÆ			return false
   876ŌåÆ		}
   877ŌåÆ
   878ŌåÆ		// Get gridPos or use default values if missing
   879ŌåÆ		gridPosA, okA := panelA["gridPos"].(map[string]interface{})
   880ŌåÆ		gridPosB, okB := panelB["gridPos"].(map[string]interface{})
   881ŌåÆ
   882ŌåÆ		// Default gridPos values (matches frontend PanelModel defaults)
   883ŌåÆ		defaultY := float64(0)
   884ŌåÆ		defaultX := float64(0)
   885ŌåÆ
   886ŌåÆ		yA := defaultY
   887ŌåÆ		if okA {
   888ŌåÆ			if y, ok := gridPosA["y"].(float64); ok {
   889ŌåÆ				yA = y
   890ŌåÆ			} else if y, ok := gridPosA["y"].(int); ok {
   891ŌåÆ				yA = float64(y)
   892ŌåÆ			}
   893ŌåÆ		}
   894ŌåÆ
   895ŌåÆ		yB := defaultY
   896ŌåÆ		if okB {
   897ŌåÆ			if y, ok := gridPosB["y"].(float64); ok {
   898ŌåÆ				yB = y
   899ŌåÆ			} else if y, ok := gridPosB["y"].(int); ok {
   900ŌåÆ				yB = float64(y)
   901ŌåÆ			}
   902ŌåÆ		}
   903ŌåÆ
   904ŌåÆ		if yA == yB {
   905ŌåÆ			xA := defaultX
   906ŌåÆ			if okA {
   907ŌåÆ				if x, ok := gridPosA["x"].(float64); ok {
   908ŌåÆ					xA = x
   909ŌåÆ				} else if x, ok := gridPosA["x"].(int); ok {
   910ŌåÆ					xA = float64(x)
   911ŌåÆ				}
   912ŌåÆ			}
   913ŌåÆ
   914ŌåÆ			xB := defaultX
   915ŌåÆ			if okB {
   916ŌåÆ				if x, ok := gridPosB["x"].(float64); ok {
   917ŌåÆ					xB = x
   918ŌåÆ				} else if x, ok := gridPosB["x"].(int); ok {
   919ŌåÆ					xB = float64(x)
   920ŌåÆ				}
   921ŌåÆ			}
   922ŌåÆ			return xA < xB
   923ŌåÆ		}
   924ŌåÆ		return yA < yB
   925ŌåÆ	})
   926ŌåÆ}
