   939ŌåÆ// applyPanelAutoMigration applies the same auto-migration logic as the frontend PanelModel constructor
   940ŌåÆfunc applyPanelAutoMigration(panel map[string]interface{}) {
   941ŌåÆ	panelType, ok := panel["type"].(string)
   942ŌåÆ	if !ok {
   943ŌåÆ		return
   944ŌåÆ	}
   945ŌåÆ
   946ŌåÆ	var newType string
   947ŌåÆ
   948ŌåÆ	// Graph needs special logic as it can be migrated to multiple panels
   949ŌåÆ	// Including graphite which was previously migrated to graph in the schema version 2 migration in DashboardMigrator.ts
   950ŌåÆ	// but this was a bug because in there graphite was set to graph, but since those migrations run
   951ŌåÆ	// after PanelModel.restoreModel where autoMigrateFrom is set, this caused the graph migration to be skipped.
   952ŌåÆ	// And this resulted in a dashboard with invalid panels.
   953ŌåÆ	if panelType == "graph" || panelType == "graphite" {
   954ŌåÆ		// Check xaxis mode for special cases
   955ŌåÆ		newType = getGraphAutoMigration(panel)
   956ŌåÆ	} else {
   957ŌåÆ		// Check autoMigrateAngular mapping
   958ŌåÆ		autoMigrateAngular := map[string]string{
   959ŌåÆ			"table-old":                "table",
   960ŌåÆ			"singlestat":               "stat",
   961ŌåÆ			"grafana-singlestat-panel": "stat",
   962ŌåÆ			"grafana-piechart-panel":   "piechart",
   963ŌåÆ			"grafana-worldmap-panel":   "geomap",
   964ŌåÆ			"natel-discrete-panel":     "state-timeline",
   965ŌåÆ		}
   966ŌåÆ
   967ŌåÆ		if mappedType, exists := autoMigrateAngular[panelType]; exists {
   968ŌåÆ			newType = mappedType
   969ŌåÆ		}
   970ŌåÆ	}
   971ŌåÆ
   972ŌåÆ	// Apply auto-migration if a new type was determined
   973ŌåÆ	if newType != "" {
   974ŌåÆ		panel["autoMigrateFrom"] = panelType
   975ŌåÆ		panel["type"] = newType
   976ŌåÆ	}
   977ŌåÆ}
   978ŌåÆ
   979ŌåÆfunc getGraphAutoMigration(panel map[string]interface{}) string {
   980ŌåÆ	newType := ""
   981ŌåÆ	if xaxis, ok := panel["xaxis"].(map[string]interface{}); ok {
   982ŌåÆ		if mode, ok := xaxis["mode"].(string); ok {
   983ŌåÆ			switch mode {
   984ŌåÆ			case "series":
   985ŌåÆ				// Check legend values for bargauge
   986ŌåÆ				if legend, ok := panel["legend"].(map[string]interface{}); ok {
   987ŌåÆ					if values, ok := legend["values"].(bool); ok && values {
   988ŌåÆ						newType = "bargauge"
   989ŌåÆ					} else {
   990ŌåÆ						newType = "barchart"
   991ŌåÆ					}
   992ŌåÆ				} else {
   993ŌåÆ					newType = "barchart"
   994ŌåÆ				}
   995ŌåÆ			case "histogram":
   996ŌåÆ				newType = "histogram"
   997ŌåÆ			}
   998ŌåÆ		}
   999ŌåÆ	}
  1000ŌåÆ
  1001ŌåÆ	// Default graph migration to timeseries
  1002ŌåÆ	if newType == "" {
  1003ŌåÆ		newType = "timeseries"
  1004ŌåÆ	}
  1005ŌåÆ
  1006ŌåÆ	return newType
  1007ŌåÆ}
