   411ŌåÆ// getPanels extracts all panels from the dashboard (including nested panels)
   412ŌåÆ// This matches the frontend's depth-first iteration order in panelIterator()
   413ŌåÆfunc getPanels(dashboard map[string]interface{}) []map[string]interface{} {
   414ŌåÆ	var panels []map[string]interface{}
   415ŌåÆ
   416ŌåÆ	// Get top-level panels
   417ŌåÆ	if dashboardPanels, ok := dashboard["panels"].([]interface{}); ok {
   418ŌåÆ		for _, panelInterface := range dashboardPanels {
   419ŌåÆ			if panel, ok := panelInterface.(map[string]interface{}); ok {
   420ŌåÆ				// Add top-level panel first
   421ŌåÆ				panels = append(panels, panel)
   422ŌåÆ
   423ŌåÆ				// Then add its nested panels (depth-first order)
   424ŌåÆ				if nestedPanels, ok := panel["panels"].([]interface{}); ok {
   425ŌåÆ					for _, nestedPanelInterface := range nestedPanels {
   426ŌåÆ						if nestedPanel, ok := nestedPanelInterface.(map[string]interface{}); ok {
   427ŌåÆ							panels = append(panels, nestedPanel)
   428ŌåÆ						}
   429ŌåÆ					}
   430ŌåÆ				}
   431ŌåÆ			}
   432ŌåÆ		}
   433ŌåÆ	}
   434ŌåÆ
   435ŌåÆ	return panels
   436ŌåÆ}
