   556ŌåÆ// filterDefaultValues removes properties that match the default values (matches frontend's isEqual logic)
   557ŌåÆfunc filterDefaultValues(panel map[string]interface{}, originalProperties map[string]bool) {
   558ŌåÆ	// Get panel type for panel-specific defaults
   559ŌåÆ	panelType := ""
   560ŌåÆ	if t, ok := panel["type"].(string); ok {
   561ŌåÆ		panelType = t
   562ŌåÆ	}
   563ŌåÆ
   564ŌåÆ	// PanelModel defaults from frontend
   565ŌåÆ	defaults := map[string]interface{}{
   566ŌåÆ		"gridPos": map[string]interface{}{
   567ŌåÆ			"x": 0, "y": 0, "h": 3, "w": 6,
   568ŌåÆ		},
   569ŌåÆ		"targets": []interface{}{
   570ŌåÆ			map[string]interface{}{"refId": "A"},
   571ŌåÆ		},
   572ŌåÆ		"cachedPluginOptions": map[string]interface{}{},
   573ŌåÆ		"transparent":         false,
   574ŌåÆ		"options":             map[string]interface{}{},
   575ŌåÆ		"links":               []interface{}{},
   576ŌåÆ		"fieldConfig": map[string]interface{}{
   577ŌåÆ			"defaults":  map[string]interface{}{},
   578ŌåÆ			"overrides": []interface{}{},
   579ŌåÆ		},
   580ŌåÆ		"title": "",
   581ŌåÆ	}
   582ŌåÆ
   583ŌåÆ	// Add panel-specific defaults
   584ŌåÆ	if panelType == "table" {
   585ŌåÆ		// Remove legacy table properties (matches frontend getSaveModel filtering)
   586ŌåÆ		// Exception: preserve original properties for old table panels with autoMigrateFrom="table-old"
   587ŌåÆ		legacyTableProps := []string{"pageSize", "scroll", "fontSize", "showHeader", "sort"}
   588ŌåÆ		for _, prop := range legacyTableProps {
   589ŌåÆ			if _, exists := panel[prop]; exists {
   590ŌåÆ				if autoMigrateFrom, hasAutoMigrate := panel["autoMigrateFrom"]; hasAutoMigrate && autoMigrateFrom == "table-old" {
   591ŌåÆ					if !originalProperties[prop] {
   592ŌåÆ						delete(panel, prop)
   593ŌåÆ					}
   594ŌåÆ				} else {
   595ŌåÆ					delete(panel, prop)
   596ŌåÆ				}
   597ŌåÆ			}
   598ŌåÆ		}
   599ŌåÆ	}
   600ŌåÆ
   601ŌåÆ	// Remove properties that match defaults, but preserve properties that were originally present
   602ŌåÆ	for prop, defaultValue := range defaults {
   603ŌåÆ		if panelValue, exists := panel[prop]; exists {
   604ŌåÆ			if isEqual(panelValue, defaultValue) {
   605ŌåÆ				// Special case: fieldConfig - handle preservation of original custom object first
   606ŌåÆ				if prop == "fieldConfig" {
   607ŌåÆ					// Check if we need to preserve the custom object before removing fieldConfig
   608ŌåÆ					if panel["_originallyHadFieldConfigCustom"] == true {
   609ŌåÆ						// Ensure fieldConfig structure exists with custom object
   610ŌåÆ						if fieldConfig, ok := panelValue.(map[string]interface{}); ok {
   611ŌåÆ							if defaults, ok := fieldConfig["defaults"].(map[string]interface{}); ok {
   612ŌåÆ								if _, hasCustom := defaults["custom"]; !hasCustom {
   613ŌåÆ									defaults["custom"] = map[string]interface{}{}
   614ŌåÆ								}
   615ŌåÆ								// Don't remove fieldConfig if we added custom back
   616ŌåÆ								continue
   617ŌåÆ							}
   618ŌåÆ						}
   619ŌåÆ					}
   620ŌåÆ					delete(panel, prop)
   621ŌåÆ				} else {
   622ŌåÆ					// Only remove if it wasn't originally present in the input
   623ŌåÆ					if !originalProperties[prop] {
   624ŌåÆ						delete(panel, prop)
   625ŌåÆ					}
   626ŌåÆ				}
   627ŌåÆ			}
   628ŌåÆ		}
   629ŌåÆ	}
   630ŌåÆ
   631ŌåÆ	// Remove empty targets arrays (frontend removes them in cleanup)
   632ŌåÆ	removeIfDefaultValue(panel, "targets", []interface{}{})
   633ŌåÆ
   634ŌåÆ	// Handle case where fieldConfig was removed but originally had custom object
   635ŌåÆ	if panel["_originallyHadFieldConfigCustom"] == true {
   636ŌåÆ		if _, hasFieldConfig := panel["fieldConfig"]; !hasFieldConfig {
   637ŌåÆ			// Recreate fieldConfig with custom object
   638ŌåÆ			panel["fieldConfig"] = map[string]interface{}{
   639ŌåÆ				"defaults": map[string]interface{}{
   640ŌåÆ					"custom": map[string]interface{}{},
   641ŌåÆ				},
   642ŌåÆ				"overrides": []interface{}{},
   643ŌåÆ			}
   644ŌåÆ		}
   645ŌåÆ	}
   646ŌåÆ
   647ŌåÆ	// Clean up fieldConfig to match frontend behavior
   648ŌåÆ	if fieldConfig, exists := panel["fieldConfig"].(map[string]interface{}); exists {
   649ŌåÆ		// Clean up fieldConfig defaults to match frontend behavior
   650ŌåÆ		if defaults, hasDefaults := fieldConfig["defaults"].(map[string]interface{}); hasDefaults {
   651ŌåÆ			// Remove properties that frontend considers as defaults and omits
   652ŌåÆ			cleanupFieldConfigDefaults(defaults, panel)
   653ŌåÆ
   654ŌåÆ			// Preserve custom object if it was originally present, even if empty
   655ŌåÆ			if panel["_originallyHadFieldConfigCustom"] == true {
   656ŌåÆ				if _, hasCustom := defaults["custom"]; !hasCustom {
   657ŌåÆ					defaults["custom"] = map[string]interface{}{}
   658ŌåÆ				}
   659ŌåÆ			}
   660ŌåÆ		}
   661ŌåÆ	}
   662ŌåÆ}
