   664ŌåÆ// isEqual checks if two values are equal (simplified version)
   665ŌåÆfunc isEqual(a, b interface{}) bool {
   666ŌåÆ	if a == nil && b == nil {
   667ŌåÆ		return true
   668ŌåÆ	}
   669ŌåÆ	if a == nil || b == nil {
   670ŌåÆ		return false
   671ŌåÆ	}
   672ŌåÆ
   673ŌåÆ	// For simple types, use direct comparison
   674ŌåÆ	switch aVal := a.(type) {
   675ŌåÆ	case bool:
   676ŌåÆ		if bVal, ok := b.(bool); ok {
   677ŌåÆ			return aVal == bVal
   678ŌåÆ		}
   679ŌåÆ	case string:
   680ŌåÆ		if bVal, ok := b.(string); ok {
   681ŌåÆ			return aVal == bVal
   682ŌåÆ		}
   683ŌåÆ	case float64:
   684ŌåÆ		if bVal, ok := b.(float64); ok {
   685ŌåÆ			return aVal == bVal
   686ŌåÆ		}
   687ŌåÆ	case []interface{}:
   688ŌåÆ		if bVal, ok := b.([]interface{}); ok {
   689ŌåÆ			if len(aVal) != len(bVal) {
   690ŌåÆ				return false
   691ŌåÆ			}
   692ŌåÆ			for i, v := range aVal {
   693ŌåÆ				if !isEqual(v, bVal[i]) {
   694ŌåÆ					return false
   695ŌåÆ				}
   696ŌåÆ			}
   697ŌåÆ			return true
   698ŌåÆ		}
   699ŌåÆ	case map[string]interface{}:
   700ŌåÆ		if bVal, ok := b.(map[string]interface{}); ok {
   701ŌåÆ			if len(aVal) != len(bVal) {
   702ŌåÆ				return false
   703ŌåÆ			}
   704ŌåÆ			for k, v := range aVal {
   705ŌåÆ				if !isEqual(v, bVal[k]) {
   706ŌåÆ					return false
   707ŌåÆ				}
   708ŌåÆ			}
   709ŌåÆ			return true
   710ŌåÆ		}
   711ŌåÆ	}
   712ŌåÆ
   713ŌåÆ	return false
   714ŌåÆ}
