   358ŌåÆ// ensureQueryIds ensures all queries have refId
   359ŌåÆfunc ensureQueryIds(panel map[string]interface{}) {
   360ŌåÆ	targets, ok := panel["targets"].([]interface{})
   361ŌåÆ	if !ok || len(targets) == 0 {
   362ŌåÆ		return
   363ŌåÆ	}
   364ŌåÆ
   365ŌåÆ	// Check if any target is missing refId
   366ŌåÆ	hasMissingRefId := false
   367ŌåÆ	for _, target := range targets {
   368ŌåÆ		if targetMap, ok := target.(map[string]interface{}); ok {
   369ŌåÆ			if targetMap["refId"] == nil {
   370ŌåÆ				hasMissingRefId = true
   371ŌåÆ				break
   372ŌåÆ			}
   373ŌåÆ		}
   374ŌåÆ	}
   375ŌåÆ
   376ŌåÆ	if hasMissingRefId {
   377ŌåÆ		// Find existing refIds
   378ŌåÆ		existingRefIds := make(map[string]bool)
   379ŌåÆ		for _, target := range targets {
   380ŌåÆ			if targetMap, ok := target.(map[string]interface{}); ok {
   381ŌåÆ				if refId, ok := targetMap["refId"].(string); ok {
   382ŌåÆ					existingRefIds[refId] = true
   383ŌåÆ				}
   384ŌåÆ			}
   385ŌåÆ		}
   386ŌåÆ
   387ŌåÆ		// Assign refIds to targets that don't have them
   388ŌåÆ		letters := "ABCDEFGHIJKLMNOPQRSTUVWXYZ"
   389ŌåÆ		letterIndex := 0
   390ŌåÆ
   391ŌåÆ		for _, target := range targets {
   392ŌåÆ			if targetMap, ok := target.(map[string]interface{}); ok {
   393ŌåÆ				if targetMap["refId"] == nil {
   394ŌåÆ					// Find next available refId
   395ŌåÆ					for letterIndex < len(letters) {
   396ŌåÆ						refId := string(letters[letterIndex])
   397ŌåÆ						if !existingRefIds[refId] {
   398ŌåÆ							targetMap["refId"] = refId
   399ŌåÆ							existingRefIds[refId] = true
   400ŌåÆ							break
   401ŌåÆ						}
   402ŌåÆ						letterIndex++
   403ŌåÆ					}
   404ŌåÆ					letterIndex++
   405ŌåÆ				}
   406ŌåÆ			}
   407ŌåÆ		}
   408ŌåÆ	}
   409ŌåÆ}
