   438ŌåÆ// cleanupPanelForSaveWithContext mimics the PanelModel.getSaveModel() behavior
   439ŌåÆ// This removes properties that shouldn't be persisted and filters out default values
   440ŌåÆfunc cleanupPanelForSaveWithContext(panel map[string]interface{}, isNested bool) {
   441ŌåÆ	// Apply auto-migration logic (matches frontend PanelModel constructor)
   442ŌåÆ	// This happens during cleanup phase to match when frontend applies auto-migration
   443ŌåÆ	// Only apply auto-migration to top-level panels, not nested ones (matches frontend behavior)
   444ŌåÆ	if !isNested {
   445ŌåÆ		applyPanelAutoMigration(panel)
   446ŌåÆ	}
   447ŌåÆ
   448ŌåÆ	// Library panel specific cleanup (matches frontend behavior)
   449ŌåÆ	// Frontend only preserves id, title, gridPos, and libraryPanel for library panels
   450ŌåÆ	if libraryPanel, hasLibraryPanel := panel["libraryPanel"]; hasLibraryPanel && libraryPanel != nil {
   451ŌåÆ		// Create a new panel with only the essential properties
   452ŌåÆ		essentialProps := map[string]interface{}{
   453ŌåÆ			"id":           panel["id"],
   454ŌåÆ			"title":        panel["title"],
   455ŌåÆ			"gridPos":      panel["gridPos"],
   456ŌåÆ			"libraryPanel": libraryPanel,
   457ŌåÆ		}
   458ŌåÆ
   459ŌåÆ		// Clear the original panel and copy back only essential properties
   460ŌåÆ		for key := range panel {
   461ŌåÆ			delete(panel, key)
   462ŌåÆ		}
   463ŌåÆ		for key, value := range essentialProps {
   464ŌåÆ			if value != nil {
   465ŌåÆ				panel[key] = value
   466ŌåÆ			}
   467ŌåÆ		}
   468ŌåÆ		return // Skip the rest of the cleanup for library panels
   469ŌåÆ	}
   470ŌåÆ
   471ŌåÆ	// Row panel specific cleanup (matches frontend behavior)
   472ŌåÆ	cleanupRowPanelProperties(panel)
   473ŌåÆ
   474ŌåÆ	// Track which properties were present in the input to preserve them even if they become empty
   475ŌåÆ	originalProperties := make(map[string]bool)
   476ŌåÆ	for key := range panel {
   477ŌåÆ		originalProperties[key] = true
   478ŌåÆ	}
   479ŌåÆ	// Properties that should never be persisted (notPersistedProperties)
   480ŌåÆ	notPersistedProps := map[string]bool{
   481ŌåÆ		"events":                  true,
   482ŌåÆ		"isViewing":               true,
   483ŌåÆ		"isEditing":               true,
   484ŌåÆ		"isInView":                true,
   485ŌåÆ		"hasRefreshed":            true,
   486ŌåÆ		"cachedPluginOptions":     true, // This is the key one causing issues
   487ŌåÆ		"plugin":                  true,
   488ŌåÆ		"queryRunner":             true,
   489ŌåÆ		"replaceVariables":        true,
   490ŌåÆ		"configRev":               true,
   491ŌåÆ		"hasSavedPanelEditChange": true,
   492ŌåÆ		"getDisplayTitle":         true,
   493ŌåÆ		"dataSupport":             true,
   494ŌåÆ		"key":                     true,
   495ŌåÆ		"isNew":                   true,
   496ŌåÆ		"refreshWhenInView":       true,
   497ŌåÆ		"scopedVars":              true, // Frontend removes scopedVars from save model
   498ŌåÆ	}
   499ŌåÆ
   500ŌåÆ	// Default values that should be filtered out if they match (defaults)
   501ŌåÆ	defaults := map[string]interface{}{
   502ŌåÆ		"gridPos": map[string]interface{}{
   503ŌåÆ			"x": float64(0), "y": float64(0), "h": float64(3), "w": float64(6),
   504ŌåÆ		},
   505ŌåÆ		"targets": []interface{}{
   506ŌåÆ			map[string]interface{}{"refId": "A"},
   507ŌåÆ		},
   508ŌåÆ		"cachedPluginOptions": map[string]interface{}{},
   509ŌåÆ		"transparent":         false,
   510ŌåÆ		"options":             map[string]interface{}{},
   511ŌåÆ		"links":               []interface{}{},
   512ŌåÆ		"fieldConfig": map[string]interface{}{
   513ŌåÆ			"defaults":  map[string]interface{}{},
   514ŌåÆ			"overrides": []interface{}{},
   515ŌåÆ		},
   516ŌåÆ		"title": "",
   517ŌåÆ	}
   518ŌåÆ
   519ŌåÆ	// Remove notPersistedProperties
   520ŌåÆ	for prop := range notPersistedProps {
   521ŌåÆ		delete(panel, prop)
   522ŌåÆ	}
   523ŌåÆ
   524ŌåÆ	// Filter out properties that match defaults
   525ŌåÆ	for prop, defaultValue := range defaults {
   526ŌåÆ		if panelValue, exists := panel[prop]; exists {
   527ŌåÆ			if isEqual(panelValue, defaultValue) {
   528ŌåÆ				delete(panel, prop)
   529ŌåÆ			}
   530ŌåÆ		}
   531ŌåÆ	}
   532ŌåÆ
   533ŌåÆ	// Remove empty transformations array unless nested panel had them originally
   534ŌåÆ	if transformations, ok := panel["transformations"].([]interface{}); ok && len(transformations) == 0 {
   535ŌåÆ		if panel["_originallyHadTransformations"] != true || !isNested {
   536ŌåÆ			delete(panel, "transformations")
   537ŌåÆ		}
   538ŌåÆ	}
   539ŌåÆ
   540ŌåÆ	// Remove null values recursively to match frontend's JSON.stringify/parse behavior
   541ŌåÆ	// Pass panel type information to help with threshold handling
   542ŌåÆ	panelType := ""
   543ŌåÆ	if t, ok := panel["type"].(string); ok {
   544ŌåÆ		panelType = t
   545ŌåÆ	}
   546ŌåÆ	removeNullValuesRecursivelyWithContext(panel, panelType)
   547ŌåÆ
   548ŌåÆ	// Filter out properties that match defaults (matches frontend's isEqual logic)
   549ŌåÆ	filterDefaultValues(panel, originalProperties)
   550ŌåÆ
   551ŌåÆ	// Clean up internal markers
   552ŌåÆ	delete(panel, "_originallyHadTransformations")
   553ŌåÆ	delete(panel, "_originallyHadFieldConfigCustom")
   554ŌåÆ}
