   785ŌåÆ// cleanupVariable cleans up individual variable properties
   786ŌåÆfunc cleanupVariable(variable map[string]interface{}) {
   787ŌåÆ	// Remove null datasource
   788ŌåÆ	removeIfDefaultValue(variable, "datasource", nil)
   789ŌåÆ
   790ŌåÆ	// Remove properties that frontend omits in getSaveModel
   791ŌåÆ	delete(variable, "index")
   792ŌåÆ
   793ŌåÆ	// Apply variable type-specific logic
   794ŌåÆ	if variableType, ok := variable["type"].(string); ok {
   795ŌåÆ		switch variableType {
   796ŌåÆ		case "query":
   797ŌåÆ			// Query variables: keep options: [] if refresh !== never (matches frontend getSaveModel logic)
   798ŌåÆ			refresh := schemaversion.GetIntValue(variable, "refresh", 1) // Default to 1 (onDashboardLoad) if not specified
   799ŌåÆ			if refresh != 0 {                                            // 0 = VariableRefreshNever
   800ŌåÆ				if _, hasOptions := variable["options"]; !hasOptions {
   801ŌåÆ					variable["options"] = []interface{}{}
   802ŌåÆ				}
   803ŌåÆ			}
   804ŌåÆ		case "constant":
   805ŌåÆ			// Constant variables: remove options completely
